export default function SpaceCard({ space, onToggleFavorite, isFavorite, commuteMins }) {
  return (
    <a href={`/spaces/${space.id}`} className="group border border-gray-100 rounded-2xl overflow-hidden shadow-card hover:-translate-y-0.5 transition block">
      <div className="h-40 bg-gradient-to-br from-brand-100 to-brand-200" />
      <div className="p-4">
        <div className="flex items-start justify-between gap-3">
          <div>
            <h3 className="text-lg font-semibold text-gray-900 group-hover:text-brand-700">{space.name}</h3>
            <p className="text-sm text-gray-600">{space.locationText}</p>
          </div>
          <div className="text-right">
            <div className="text-brand-700 font-semibold">₹{space.pricePerDay}/day</div>
            <div className="text-sm text-gray-500">★ {space.rating}</div>
          </div>
        </div>
        {typeof commuteMins === 'number' && (
          <div className="mt-2 text-xs text-gray-600">~ {commuteMins} min commute</div>
        )}
        <div className="mt-3 flex flex-wrap gap-2">
          {space.amenities.slice(0, 4).map((a) => (
            <span key={a} className="text-xs px-2 py-1 rounded-full bg-gray-100 text-gray-700">{a}</span>
          ))}
        </div>
        {onToggleFavorite && (
          <button
            type="button"
            className={`mt-4 text-sm px-3 py-1.5 rounded-lg border ${isFavorite ? 'border-brand-600 text-brand-700 bg-brand-50' : 'border-gray-200 text-gray-700 hover:border-brand-300'}`}
            onClick={(e) => {
              e.preventDefault();
              onToggleFavorite(space.id);
            }}
          >
            {isFavorite ? '★ Saved' : '☆ Save'}
          </button>
        )}
      </div>
    </a>
  );
}
